     1→/**
     2→ * Notes Store
     3→ *
     4→ * Zustand store for managing notes state
     5→ * Persisted to IndexedDB via syncedStorage
     6→ */
     7→
     8→import { create } from 'zustand';
     9→import { persist, createJSONStorage } from 'zustand/middleware';
    10→import { v4 as uuidv4 } from 'uuid';
    11→import type {
    12→  Note,
    13→  NoteUpdate,
    14→  NoteSortConfig,
    15→  NoteFilter,
    16→} from '../types/notes';
    17→import { NOTE_CONSTANTS } from '../types/notes';
    18→import { createSyncedStorage } from '../lib/syncedStorage';
    19→import { useUndoStore } from './useUndoStore';
    20→
    21→/**
    22→ * Notes Store State
    23→ */
    24→interface NotesStore {
    25→  // State
    26→  notes: Record<string, Note>; // Map of note ID -> Note
    27→  activeNoteId: string | null; // Currently open note
    28→  sortConfig: NoteSortConfig;
    29→  filter: NoteFilter;
    30→
    31→  // Actions - CRUD
    32→  createNote: (params?: Partial<Note>) => Note;
    33→  getNote: (id: string) => Note | undefined;
    34→  updateNote: (id: string, updates: NoteUpdate) => void;
    35→  deleteNote: (id: string) => void;
    36→  duplicateNote: (id: string) => Note | null;
    37→
    38→  // Actions - Bulk operations
    39→  deleteNotes: (ids: string[]) => void;
    40→  moveNotesToFolder: (noteIds: string[], folderId: string | null) => void;
    41→  archiveNotes: (noteIds: string[]) => void;
    42→  unarchiveNotes: (noteIds: string[]) => void;
    43→
    44→  // Actions - Queries
    45→  getAllNotes: () => Note[];
    46→  getNotesByFolder: (folderId: string | null) => Note[];
    47→  getNotesBy: (predicate: (note: Note) => boolean) => Note[];
    48→  searchNotes: (query: string) => Note[];
    49→
    50→  // Actions - Pin/Archive/Favorite
    51→  togglePin: (id: string) => void;
    52→  toggleArchive: (id: string) => void;
    53→  toggleFavorite: (id: string) => void;
    54→
    55→  // Actions - Tags
    56→  addTag: (id: string, tag: string) => void;
    57→  removeTag: (id: string, tag: string) => void;
    58→  getAllTags: () => string[];
    59→
    60→  // Actions - UI state
    61→  setActiveNote: (id: string | null) => void;
    62→  setSortConfig: (config: NoteSortConfig) => void;
    63→  setFilter: (filter: NoteFilter) => void;
    64→
    65→  // Actions - Utility
    66→  getNoteCount: () => number;
    67→  getNotesInFolder: (folderId: string | null) => Note[];
    68→  exportNotes: () => Note[];
    69→  importNotes: (notes: Note[], merge: boolean) => void;
    70→  clearAllNotes: () => void;
    71→}
    72→
    73→/**
    74→ * Default note values
    75→ */
    76→const createDefaultNote = (overrides?: Partial<Note>): Note => {
    77→  const now = new Date();
    78→  return {
    79→    id: uuidv4(),
    80→    folderId: null,
    81→    title: NOTE_CONSTANTS.DEFAULT_TITLE,
    82→    content: '', // Empty Lexical state
    83→    contentText: '',
    84→    tags: [],
    85→    createdAt: now,
    86→    updatedAt: now,
    87→    isPinned: false,
    88→    isArchived: false,
    89→    ...overrides,
    90→  };
    91→};
    92→
    93→/**
    94→ * Sort notes based on sort config
    95→ */
    96→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
    97→  const sorted = [...notes];
    98→
    99→  sorted.sort((a, b) => {
   100→    let comparison = 0;
   101→
   102→    switch (config.field) {
   103→      case 'title':
   104→        comparison = a.title.localeCompare(b.title);
   105→        break;
   106→      case 'createdAt':
   107→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   108→        break;
   109→      case 'updatedAt':
   110→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   111→        break;
   112→      case 'manual':
   113→        // Manual sort - preserve order (could add sortOrder field in future)
   114→        comparison = 0;
   115→        break;
   116→    }
   117→
   118→    return config.order === 'asc' ? comparison : -comparison;
   119→  });
   120→
   121→  // Always pin pinned notes to top
   122→  return sorted.sort((a, b) => {
   123→    if (a.isPinned && !b.isPinned) return -1;
   124→    if (!a.isPinned && b.isPinned) return 1;
   125→    return 0;
   126→  });
   127→};
   128→
   129→/**
   130→ * Filter notes based on filter type
   131→ */
   132→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   133→  switch (filter) {
   134→    case 'favorites':
   135→      return notes.filter((note) => note.isFavorite);
   136→    case 'pinned':
   137→      return notes.filter((note) => note.isPinned);
   138→    case 'archived':
   139→      return notes.filter((note) => note.isArchived);
   140→    case 'unarchived':
   141→      return notes.filter((note) => !note.isArchived);
   142→    case 'all':
   143→    default:
   144→      return notes;
   145→  }
   146→};
   147→
   148→/**
   149→ * Create the Notes store
   150→ */
   151→export const useNotesStore = create<NotesStore>()(
   152→  persist(
   153→    (set, get) => ({
   154→      // Initial state
   155→      notes: {},
   156→      activeNoteId: null,
   157→      sortConfig: {
   158→        field: 'updatedAt',
   159→        order: 'desc',
   160→      },
   161→      filter: 'unarchived',
   162→
   163→      // CRUD Operations
   164→      createNote: (params) => {
   165→        const newNote = createDefaultNote(params);
   166→        set((state) => ({
   167→          notes: {
   168→            ...state.notes,
   169→            [newNote.id]: newNote,
   170→          },
   171→          activeNoteId: newNote.id, // Auto-select new note
   172→        }));
   173→        console.log('✅ Note created:', newNote.id);
   174→        return newNote;
   175→      },
   176→
   177→      getNote: (id) => {
   178→        return get().notes[id];
   179→      },
   180→
   181→      updateNote: (id, updates) => {
   182→        const note = get().notes[id];
   183→        if (!note) {
   184→          console.warn(`Note ${id} not found`);
   185→          return;
   186→        }
   187→
   188→        // Only update timestamp if content/title/tags actually changed
   189→        // Skip timestamp update for UI-only changes (like folderId without content change)
   190→        const shouldUpdateTimestamp =
   191→          updates.content !== undefined ||
   192→          updates.title !== undefined ||
   193→          updates.tags !== undefined;
   194→
   195→        set((state) => ({
   196→          notes: {
   197→            ...state.notes,
   198→            [id]: {
   199→              ...note,
   200→              ...updates,
   201→              ...(shouldUpdateTimestamp ? { updatedAt: new Date() } : {}),
   202→            },
   203→          },
   204→        }));
   205→        console.log('✅ Note updated:', id, shouldUpdateTimestamp ? '(timestamp updated)' : '(no timestamp change)');
   206→      },
   207→
   208→      deleteNote: (id) => {
   209→        // Save note for undo
   210→        const noteToDelete = get().notes[id];
   211→        if (!noteToDelete) {
   212→          console.warn(`Note ${id} not found`);
   213→          return;
   214→        }
   215→
   216→        // Store the previous activeNoteId for undo
   217→        const wasActive = get().activeNoteId === id;
   218→
   219→        // Delete the note
   220→        set((state) => {
   221→          const { [id]: deleted, ...remainingNotes } = state.notes;
   222→          return {
   223→            notes: remainingNotes,
   224→            activeNoteId: state.activeNoteId === id ? null : state.activeNoteId,
   225→          };
   226→        });
   227→
   228→        console.log('✅ Note deleted:', id);
   229→
   230→        // Delete associated images from IndexedDB (async, fire-and-forget)
   231→        import('../services/indexedDB').then(({ indexedDBService }) => {
   232→          indexedDBService.deleteNoteImages(id).catch((err) => {
   233→            console.error('Failed to delete note images:', err);
   234→          });
   235→        });
   236→
   237→        // Add undo action
   238→        useUndoStore.getState().addUndoAction(
   239→          `Note "${noteToDelete.title}" deleted`,
   240→          () => {
   241→            // Restore the note
   242→            set((state) => ({
   243→              notes: {
   244→                ...state.notes,
   245→                [id]: noteToDelete,
   246→              },
   247→              activeNoteId: wasActive ? id : state.activeNoteId,
   248→            }));
   249→            console.log('✅ Note restored (undo):', id);
   250→          }
   251→        );
   252→      },
   253→
   254→      duplicateNote: (id) => {
   255→        const original = get().notes[id];
   256→        if (!original) {
   257→          console.warn(`Note ${id} not found`);
   258→          return null;
   259→        }
   260→
   261→        const duplicate = createDefaultNote({
   262→          ...original,
   263→          title: `${original.title} (Copy)`,
   264→          isPinned: false, // Don't copy pin status
   265→        });
   266→
   267→        set((state) => ({
   268→          notes: {
   269→            ...state.notes,
   270→            [duplicate.id]: duplicate,
   271→          },
   272→        }));
   273→
   274→        console.log('✅ Note duplicated:', id, '→', duplicate.id);
   275→        return duplicate;
   276→      },
   277→
   278→      // Bulk operations
   279→      deleteNotes: (ids) => {
   280→        set((state) => {
   281→          const remainingNotes = { ...state.notes };
   282→          ids.forEach((id) => delete remainingNotes[id]);
   283→          return {
   284→            notes: remainingNotes,
   285→            activeNoteId: ids.includes(state.activeNoteId || '')
   286→              ? null
   287→              : state.activeNoteId,
   288→          };
   289→        });
   290→        console.log(`✅ Deleted ${ids.length} notes`);
   291→
   292→        // Delete associated images from IndexedDB (async, fire-and-forget)
   293→        import('../services/indexedDB').then(({ indexedDBService }) => {
   294→          ids.forEach((id) => {
   295→            indexedDBService.deleteNoteImages(id).catch((err) => {
   296→              console.error(`Failed to delete images for note ${id}:`, err);
   297→            });
   298→          });
   299→        });
   300→      },
   301→
   302→      moveNotesToFolder: (noteIds, folderId) => {
   303→        set((state) => {
   304→          const updatedNotes = { ...state.notes };
   305→          noteIds.forEach((id) => {
   306→            if (updatedNotes[id]) {
   307→              updatedNotes[id] = {
   308→                ...updatedNotes[id],
   309→                folderId,
   310→                updatedAt: new Date(),
   311→              };
   312→            }
   313→          });
   314→          return { notes: updatedNotes };
   315→        });
   316→        console.log(`✅ Moved ${noteIds.length} notes to folder:`, folderId);
   317→      },
   318→
   319→      archiveNotes: (noteIds) => {
   320→        set((state) => {
   321→          const updatedNotes = { ...state.notes };
   322→          noteIds.forEach((id) => {
   323→            if (updatedNotes[id]) {
   324→              updatedNotes[id] = {
   325→                ...updatedNotes[id],
   326→                isArchived: true,
   327→                updatedAt: new Date(),
   328→              };
   329→            }
   330→          });
   331→          return { notes: updatedNotes };
   332→        });
   333→        console.log(`✅ Archived ${noteIds.length} notes`);
   334→      },
   335→
   336→      unarchiveNotes: (noteIds) => {
   337→        set((state) => {
   338→          const updatedNotes = { ...state.notes };
   339→          noteIds.forEach((id) => {
   340→            if (updatedNotes[id]) {
   341→              updatedNotes[id] = {
   342→                ...updatedNotes[id],
   343→                isArchived: false,
   344→                updatedAt: new Date(),
   345→              };
   346→            }
   347→          });
   348→          return { notes: updatedNotes };
   349→        });
   350→        console.log(`✅ Unarchived ${noteIds.length} notes`);
   351→      },
   352→
   353→      // Queries
   354→      getAllNotes: () => {
   355→        const state = get();
   356→        const notes = Object.values(state.notes);
   357→        const filtered = filterNotes(notes, state.filter);
   358→        return sortNotes(filtered, state.sortConfig);
   359→      },
   360→
   361→      getNotesByFolder: (folderId) => {
   362→        const state = get();
   363→        const notes = Object.values(state.notes).filter(
   364→          (note) => note.folderId === folderId
   365→        );
   366→        const filtered = filterNotes(notes, state.filter);
   367→        return sortNotes(filtered, state.sortConfig);
   368→      },
   369→
   370→      getNotesBy: (predicate) => {
   371→        const notes = Object.values(get().notes).filter(predicate);
   372→        return sortNotes(notes, get().sortConfig);
   373→      },
   374→
   375→      searchNotes: (query) => {
   376→        if (!query.trim()) return [];
   377→
   378→        const lowerQuery = query.toLowerCase();
   379→        const notes = Object.values(get().notes).filter((note) => {
   380→          // Search in title, content text, and tags
   381→          return (
   382→            note.title.toLowerCase().includes(lowerQuery) ||
   383→            note.contentText.toLowerCase().includes(lowerQuery) ||
   384→            note.tags.some((tag) => tag.toLowerCase().includes(lowerQuery))
   385→          );
   386→        });
   387→
   388→        return sortNotes(notes, get().sortConfig);
   389→      },
   390→
   391→      // Pin/Archive
   392→      togglePin: (id) => {
   393→        const note = get().notes[id];
   394→        if (!note) return;
   395→
   396→        set((state) => ({
   397→          notes: {
   398→            ...state.notes,
   399→            [id]: {
   400→              ...note,
   401→              isPinned: !note.isPinned,
   402→              updatedAt: new Date(),
   403→            },
   404→          },
   405→        }));
   406→        console.log(`✅ Toggled pin for note: ${id} (${!note.isPinned})`);
   407→      },
   408→
   409→      toggleArchive: (id) => {
   410→        const note = get().notes[id];
   411→        if (!note) return;
   412→
   413→        set((state) => ({
   414→          notes: {
   415→            ...state.notes,
   416→            [id]: {
   417→              ...note,
   418→              isArchived: !note.isArchived,
   419→              updatedAt: new Date(),
   420→            },
   421→          },
   422→        }));
   423→        console.log(`✅ Toggled archive for note: ${id} (${!note.isArchived})`);
   424→      },
   425→
   426→      toggleFavorite: (id) => {
   427→        const note = get().notes[id];
   428→        if (!note) return;
   429→
   430→        set((state) => ({
   431→          notes: {
   432→            ...state.notes,
   433→            [id]: {
   434→              ...note,
   435→              isFavorite: !note.isFavorite,
   436→              updatedAt: new Date(),
   437→            },
   438→          },
   439→        }));
   440→        console.log(`✅ Toggled favorite for note: ${id} (${!note.isFavorite})`);
   441→      },
   442→
   443→      // Tags
   444→      addTag: (id, tag) => {
   445→        const note = get().notes[id];
   446→        if (!note) return;
   447→
   448→        // Don't add duplicate tags
   449→        if (note.tags.includes(tag)) return;
   450→
   451→        // Check max tags limit
   452→        if (note.tags.length >= NOTE_CONSTANTS.MAX_TAGS) {
   453→          console.warn(`Max tags (${NOTE_CONSTANTS.MAX_TAGS}) reached`);
   454→          return;
   455→        }
   456→
   457→        set((state) => ({
   458→          notes: {
   459→            ...state.notes,
   460→            [id]: {
   461→              ...note,
   462→              tags: [...note.tags, tag],
   463→              updatedAt: new Date(),
   464→            },
   465→          },
   466→        }));
   467→        console.log(`✅ Added tag "${tag}" to note: ${id}`);
   468→      },
   469→
   470→      removeTag: (id, tag) => {
   471→        const note = get().notes[id];
   472→        if (!note) return;
   473→
   474→        set((state) => ({
   475→          notes: {
   476→            ...state.notes,
   477→            [id]: {
   478→              ...note,
   479→              tags: note.tags.filter((t) => t !== tag),
   480→              updatedAt: new Date(),
   481→            },
   482→          },
   483→        }));
   484→        console.log(`✅ Removed tag "${tag}" from note: ${id}`);
   485→      },
   486→
   487→      getAllTags: () => {
   488→        const notes = Object.values(get().notes);
   489→        const tagSet = new Set<string>();
   490→        notes.forEach((note) => {
   491→          note.tags.forEach((tag) => tagSet.add(tag));
   492→        });
   493→        return Array.from(tagSet).sort();
   494→      },
   495→
   496→      // UI state
   497→      setActiveNote: (id) => {
   498→        set({ activeNoteId: id });
   499→        console.log('✅ Active note set:', id);
   500→      },
   501→
   502→      setSortConfig: (config) => {
   503→        set({ sortConfig: config });
   504→        console.log('✅ Sort config updated:', config);
   505→      },
   506→
   507→      setFilter: (filter) => {
   508→        set({ filter });
   509→        console.log('✅ Filter updated:', filter);
   510→      },
   511→
   512→      // Utility
   513→      getNoteCount: () => {
   514→        return Object.keys(get().notes).length;
   515→      },
   516→
   517→      getNotesInFolder: (folderId) => {
   518→        return Object.values(get().notes).filter(
   519→          (note) => note.folderId === folderId
   520→        );
   521→      },
   522→
   523→      exportNotes: () => {
   524→        return Object.values(get().notes);
   525→      },
   526→
   527→      importNotes: (notes, merge) => {
   528→        if (!merge) {
   529→          // Replace all notes
   530→          set({
   531→            notes: Object.fromEntries(notes.map((note) => [note.id, note])),
   532→            activeNoteId: null,
   533→          });
   534→          console.log(`✅ Imported ${notes.length} notes (replace mode)`);
   535→        } else {
   536→          // Merge with existing notes
   537→          set((state) => {
   538→            const updatedNotes = { ...state.notes };
   539→            notes.forEach((note) => {
   540→              updatedNotes[note.id] = note;
   541→            });
   542→            return { notes: updatedNotes };
   543→          });
   544→          console.log(`✅ Imported ${notes.length} notes (merge mode)`);
   545→        }
   546→      },
   547→
   548→      clearAllNotes: () => {
   549→        set({ notes: {}, activeNoteId: null });
   550→        console.log('✅ All notes cleared');
   551→      },
   552→    }),
   553→    {
   554→      name: 'notes', // IndexedDB key
   555→      storage: createJSONStorage(() => createSyncedStorage()),
   556→      partialize: (state) => ({
   557→        // Only persist notes, not UI state
   558→        notes: state.notes,
   559→      }),
   560→      // Handle date serialization
   561→      onRehydrateStorage: () => (state) => {
   562→        console.log('🔄 Notes store rehydrating...', state);
   563→        if (state) {
   564→          try {
   565→            // Ensure notes object exists and is valid
   566→            if (state.notes && typeof state.notes === 'object') {
   567→              // Convert date strings back to Date objects
   568→              Object.values(state.notes).forEach((note) => {
   569→                if (typeof note.createdAt === 'string') {
   570→                  note.createdAt = new Date(note.createdAt);
   571→                }
   572→                if (typeof note.updatedAt === 'string') {
   573→                  note.updatedAt = new Date(note.updatedAt);
   574→                }
   575→              });
   576→            } else {
   577→              console.warn('⚠️ Corrupted notes data detected, resetting to empty');
   578→              state.notes = {};
   579→            }
   580→          } catch (err) {
   581→            console.error('❌ Error during notes store rehydration:', err);
   582→            // Reset to safe defaults
   583→            state.notes = {};
   584→            state.activeNoteId = null;
   585→          }
   586→        }
   587→        console.log('✅ Notes store rehydrated', state);
   588→      },
   589→    }
   590→  )
   591→);
   592→
   593→/**
   594→ * Selector hooks for optimized re-renders
   595→ */
   596→export const useActiveNote = () =>
   597→  useNotesStore((state) => {
   598→    const activeId = state.activeNoteId;
   599→    return activeId ? state.notes[activeId] : null;
   600→  });
   601→
   602→export const useNotesByFolder = (folderId: string | null) =>
   603→  useNotesStore((state) => state.getNotesByFolder(folderId));
   604→
   605→export const useAllTags = () => useNotesStore((state) => state.getAllTags());
