    37→  updateColumn: (id: string, updates: Partial<KanbanColumn>) => void;
    38→  deleteColumn: (id: string) => void;
    39→  reorderColumns: (columnIds: string[]) => void;
    40→  replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => void;
