   100→
   101→export const useKanbanStore = create<KanbanStore>()(
   102→  persist(
   103→    (set, get) => ({
   104→      // Initial state
   105→      tasks: [],
   106→      columns: DEFAULT_COLUMNS,
   107→      dependencies: [], // Phase 5: Task dependencies
   108→      archivedTasks: [], // Phase A: Archived tasks
   109→      nextCardNumber: 1, // Phase A: Auto-incrementing card number counter
   110→      visibleColumns: 5, // UI: Number of columns visible before scrolling (default: 5)
   111→      undoHistory: [], // Undo system: stores last 5 actions
   112→
   113→      // ==================== TASK ACTIONS ====================
   114→
   115→      addTask: (taskData) => {
   116→        const currentNumber = get().nextCardNumber || 1;
   117→
   118→        const newTask: Task = {
   119→          ...taskData,
   120→          id: Date.now().toString(),
   121→          created: new Date().toISOString(),
   122→          cardNumber: currentNumber, // Phase A: Assign auto-incrementing card number
   123→          checklist: [],
   124→          comments: [],
   125→          activityLog: [],
   126→        };
   127→
   128→        set((state) => ({
   129→          tasks: [...state.tasks, newTask],
   130→          nextCardNumber: currentNumber + 1, // Increment counter
   131→        }));
   132→
   133→        // Log creation
   134→        get().logActivity(newTask.id, {
   135→          action: 'created',
   136→        });
   137→      },
   138→
   139→      updateTask: (id, updates) => {
   140→        const oldTask = get().tasks.find((t) => t.id === id);
   141→        if (!oldTask) return;
   142→
   143→        set((state) => ({
   144→          tasks: state.tasks.map((task) =>
   145→            task.id === id ? { ...task, ...updates } : task
   146→          ),
   147→        }));
   148→
   149→        // Log updates (track specific fields)
   150→        Object.keys(updates).forEach((field) => {
   151→          if (field !== 'activityLog') { // Don't log the log itself
   152→            get().logActivity(id, {
   153→              action: 'updated',
   154→              field,
   155→              oldValue: String(oldTask[field as keyof Task] ?? ''),
   156→              newValue: String(updates[field as keyof Task] ?? ''),
   157→            });
   158→          }
   159→        });
   160→      },
   161→
   162→      deleteTask: (id) =>
   163→        set((state) => ({
   164→          tasks: state.tasks.filter((task) => task.id !== id),
   165→        })),
   166→
   167→      moveTask: (id, newStatus) => {
   168→        const oldTask = get().tasks.find((t) => t.id === id);
   169→        if (!oldTask) return;
   170→
   171→        // PHASE 5 PART 6: Validate dependencies before moving to "done"
   172→        if (newStatus === 'done') {
   173→          const blockers = get().getBlockers(id);
   174→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   175→
   176→          if (incompleteBlockers.length > 0) {
   177→            console.warn(
   178→              `Cannot complete task "${oldTask.title}": Blocked by ${incompleteBlockers.length} incomplete task(s)`
   179→            );
   180→            // TODO: Show toast notification in UI
   181→            return; // Prevent move
   182→          }
   183→        }
   184→
   185→        // PHASE A: Track when task is completed (for auto-archive)
   186→        const updates: Partial<Task> = { status: newStatus };
   187→        if (newStatus === 'done' && oldTask.status !== 'done') {
   188→          updates.lastCompletedAt = new Date().toISOString();
   189→        }
   190→
   191→        set((state) => ({
   192→          tasks: state.tasks.map((task) =>
   193→            task.id === id ? { ...task, ...updates } : task
   194→          ),
   195→        }));
   196→
   197→        // Log move
   198→        get().logActivity(id, {
   199→          action: 'moved',
   200→          field: 'status',
   201→          oldValue: oldTask.status,
   202→          newValue: newStatus,
   203→        });
   204→      },
   205→
   206→      getTasksByStatus: (status) => {
   207→        return get().tasks.filter((task) => task.status === status);
   208→      },
   209→
   210→      // ==================== COLUMN ACTIONS ====================
   211→
   212→      addColumn: (columnData) => {
   213→        const columns = get().columns;
   214→        const newColumn: KanbanColumn = {
   215→          ...columnData,
   216→          id: `col-${Date.now()}`,
   217→          order: columns.length,
   218→        };
   219→
   220→        set((state) => ({
   221→          columns: [...state.columns, newColumn],
   222→        }));
   223→      },
   224→
   225→      updateColumn: (id, updates) => {
   226→        set((state) => ({
   227→          columns: state.columns.map((col) =>
   228→            col.id === id ? { ...col, ...updates } : col
   229→          ),
   230→        }));
   231→      },
   232→
   233→      deleteColumn: (id) => {
   234→        const state = get();
   235→        const columnToDelete = state.columns.find(col => col.id === id);
   236→
   237→        if (!columnToDelete) {
   238→          console.warn(`deleteColumn: Column with id '${id}' not found`);
   239→          return;
   240→        }
   241→
   242→        // Save undo entry BEFORE making changes
   243→        get().addToUndoHistory({
   244→          action: 'deleteColumn',
   245→          description: `Deleted column '${columnToDelete.title}'`,
   246→          previousState: {
   247→            columns: state.columns,
   248→            tasks: state.tasks,
   249→          },
   250→        });
   251→
   252→        // Find first remaining column (fallback, not hardcoded 'backlog')
   253→        const firstRemainingColumn = state.columns.find(col => col.id !== id);
   254→
   255→        if (!firstRemainingColumn) {
   256→          console.error('deleteColumn: Cannot delete last column');
   257→          return;
   258→        }
   259→
   260→        // Move all tasks from deleted column to first remaining column
   261→        set((state) => ({
   262→          columns: state.columns.filter((col) => col.id !== id),
   263→          tasks: state.tasks.map((task) =>
   264→            task.status === id as TaskStatus
   265→              ? { ...task, status: firstRemainingColumn.id as TaskStatus }
   266→              : task
   267→          ),
   268→        }));
   269→      },
   270→
   271→      reorderColumns: (columnIds) => {
   272→        const columns = get().columns;
   273→        const reordered = columnIds
   274→          .map((id) => columns.find((col) => col.id === id))
   275→          .filter((col): col is KanbanColumn => col !== undefined)
   276→          .map((col, index) => ({ ...col, order: index }));
   277→
   278→        set({ columns: reordered });
   279→      },
   280→
   281→      replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => {
   282→        const state = get();
   283→
   284→        // Save undo entry BEFORE making changes
   285→        get().addToUndoHistory({
   286→          action: 'replaceAllColumns',
   287→          description: `Applied template`,
   288→          previousState: {
   289→            columns: state.columns,
   290→            tasks: state.tasks,
   291→          },
   292→        });
   293→
   294→        // Generate new columns with fresh IDs and correct order
   295→        const columns: KanbanColumn[] = newColumns.map((col, index) => ({
   296→          ...col,
   297→          id: `col-${Date.now()}-${index}`,
   298→          order: index,
   299→        }));
   300→
   301→        if (columns.length === 0) {
   302→          console.error('replaceAllColumns: No columns provided');
   303→          return;
   304→        }
   305→
   306→        // Smart mapping: Try to preserve task positions based on column titles
   307→        const tasks = state.tasks.map(task => {
   308→          const oldColumn = state.columns.find(c => c.id === task.status);
   309→          if (!oldColumn) {
   310→            // Task has invalid status, move to first column
   311→            return { ...task, status: columns[0].id as TaskStatus };
   312→          }
   313→
   314→          // Try exact match first (case-insensitive)
   315→          let newColumn = columns.find(c =>
   316→            c.title.toLowerCase() === oldColumn.title.toLowerCase()
   317→          );
   318→
   319→          // If no exact match, try partial match (contains)
   320→          if (!newColumn) {
   321→            newColumn = columns.find(c =>
   322→              c.title.toLowerCase().includes(oldColumn.title.toLowerCase()) ||
   323→              oldColumn.title.toLowerCase().includes(c.title.toLowerCase())
   324→            );
   325→          }
   326→
   327→          // Fallback: first column
   328→          if (!newColumn) {
   329→            newColumn = columns[0];
   330→          }
   331→
   332→          return { ...task, status: newColumn.id as TaskStatus };
   333→        });
   334→
   335→        set({ columns, tasks });
   336→      },
   337→
   338→      // ==================== CHECKLIST ACTIONS ====================
   339→
   340→      addChecklistItem: (taskId, text) => {
   341→        const task = get().tasks.find((t) => t.id === taskId);
   342→        if (!task) return;
   343→
   344→        const newItem: ChecklistItem = {
