   358→        }));
   359→
   360→        // Log checklist update
   361→        get().logActivity(taskId, {
   362→          action: 'checklist_updated',
   363→          newValue: `Added: ${text}`,
   364→        });
   365→      },
   366→
   367→      updateChecklistItem: (taskId, itemId, updates) => {
   368→        set((state) => ({
   369→          tasks: state.tasks.map((t) =>
   370→            t.id === taskId
   371→              ? {
   372→                  ...t,
   373→                  checklist: (t.checklist || []).map((item) =>
   374→                    item.id === itemId ? { ...item, ...updates } : item
   375→                  ),
   376→                }
   377→              : t
   378→          ),
   379→        }));
   380→      },
   381→
   382→      deleteChecklistItem: (taskId, itemId) => {
   383→        const task = get().tasks.find((t) => t.id === taskId);
   384→        if (!task) return;
   385→
   386→        const item = task.checklist?.find((i) => i.id === itemId);
   387→        if (!item) return;
   388→
   389→        set((state) => ({
   390→          tasks: state.tasks.map((t) =>
   391→            t.id === taskId
   392→              ? {
   393→                  ...t,
   394→                  checklist: (t.checklist || []).filter((i) => i.id !== itemId),
   395→                }
   396→              : t
   397→          ),
   398→        }));
   399→
   400→        // Log deletion
   401→        get().logActivity(taskId, {
   402→          action: 'checklist_updated',
   403→          oldValue: `Removed: ${item.text}`,
   404→        });
   405→      },
   406→
   407→      toggleChecklistItem: (taskId, itemId) => {
   408→        const task = get().tasks.find((t) => t.id === taskId);
   409→        if (!task) return;
   410→
   411→        const item = task.checklist?.find((i) => i.id === itemId);
   412→        if (!item) return;
   413→
   414→        set((state) => ({
   415→          tasks: state.tasks.map((t) =>
   416→            t.id === taskId
   417→              ? {
   418→                  ...t,
   419→                  checklist: (t.checklist || []).map((i) =>
   420→                    i.id === itemId ? { ...i, completed: !i.completed } : i
   421→                  ),
   422→                }
   423→              : t
   424→          ),
   425→        }));
   426→
   427→        // Log toggle
   428→        get().logActivity(taskId, {
   429→          action: 'checklist_updated',
   430→          newValue: `${!item.completed ? 'Completed' : 'Unchecked'}: ${item.text}`,
   431→        });
   432→      },
   433→
   434→      reorderChecklistItems: (taskId, itemIds) => {
   435→        const task = get().tasks.find((t) => t.id === taskId);
   436→        if (!task) return;
   437→
   438→        const reordered = itemIds
   439→          .map((id) => task.checklist?.find((item) => item.id === id))
   440→          .filter((item): item is ChecklistItem => item !== undefined)
   441→          .map((item, index) => ({ ...item, order: index }));
   442→
   443→        set((state) => ({
   444→          tasks: state.tasks.map((t) =>
   445→            t.id === taskId ? { ...t, checklist: reordered } : t
   446→          ),
   447→        }));
   448→      },
   449→
   450→      // ==================== COMMENT ACTIONS ====================
   451→
   452→      addComment: (taskId, text) => {
