   483→                    c.id === commentId
   484→                      ? { ...c, text, updatedAt: new Date().toISOString() }
   485→                      : c
   486→                  ),
   487→                }
   488→              : t
   489→          ),
   490→        }));
   491→      },
   492→
   493→      deleteComment: (taskId, commentId) => {
   494→        set((state) => ({
   495→          tasks: state.tasks.map((t) =>
   496→            t.id === taskId
   497→              ? {
   498→                  ...t,
