   529→      },
   530→
   531→      // ==================== UNDO SYSTEM ====================
   532→
   533→      addToUndoHistory: (entry) => {
   534→        const newEntry: UndoHistoryEntry = {
   535→          ...entry,
   536→          id: `undo-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
   537→          timestamp: new Date().toISOString(),
   538→        };
   539→
   540→        set((state) => ({
   541→          undoHistory: [
   542→            ...state.undoHistory,
   543→            newEntry,
   544→          ].slice(-5), // Keep last 5 entries max (prevent memory bloat)
   545→        }));
   546→      },
   547→
   548→      undo: () => {
   549→        const history = get().undoHistory;
   550→        if (history.length === 0) {
   551→          console.warn('undo: No undo history available');
   552→          return;
