   554→
   555→        // Get most recent entry
   556→        const lastEntry = history[history.length - 1];
   557→
   558→        // Restore previous state
   559→        set({
   560→          columns: lastEntry.previousState.columns,
   561→          tasks: lastEntry.previousState.tasks,
   562→          undoHistory: history.slice(0, -1), // Remove this entry from history
   563→        });
   564→      },
