   602→            });
   603→          }
   604→        });
   605→      },
   606→
   607→      bulkUpdatePriority: (taskIds, newPriority) => {
   608→        const state = get();
   609→
   610→        // Save undo state
   611→        get().addToUndoHistory({
   612→          action: 'bulkDelete',
   613→          description: `Changed priority of ${taskIds.length} tasks`,
   614→          previousState: {
   615→            columns: state.columns,
   616→            tasks: state.tasks,
   617→          },
   618→        });
   619→
   620→        set((state) => ({
   621→          tasks: state.tasks.map((task) =>
   622→            taskIds.includes(task.id)
   623→              ? { ...task, priority: newPriority }
   624→              : task
   625→          ),
   626→        }));
   627→
   628→        // Log activity for each task
   629→        taskIds.forEach(taskId => {
   630→          const task = state.tasks.find(t => t.id === taskId);
   631→          if (task) {
   632→            get().logActivity(taskId, {
   633→              action: 'updated',
   634→              field: 'priority',
   635→              oldValue: task.priority,
