   638→          }
   639→        });
   640→      },
   641→
   642→      bulkDeleteTasks: (taskIds) => {
   643→        const state = get();
   644→
   645→        // Save undo state
   646→        get().addToUndoHistory({
   647→          action: 'bulkDelete',
   648→          description: `Deleted ${taskIds.length} tasks`,
   649→          previousState: {
   650→            columns: state.columns,
   651→            tasks: state.tasks,
   652→          },
   653→        });
   654→
   655→        set((state) => ({
