   658→      },
   659→
   660→      // ==================== PHASE 5: SUBTASK ACTIONS ====================
   661→
   662→      addSubtask: (taskId, subtaskData) => {
   663→        set((state) => ({
   664→          tasks: state.tasks.map((task) => {
   665→            if (task.id === taskId) {
   666→              const subtasks = task.subtasks || [];
   667→              const newSubtask: Subtask = {
   668→                ...subtaskData,
   669→                id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
   670→                parentTaskId: taskId,
   671→                order: subtasks.length,
   672→                createdAt: new Date().toISOString(),
   673→              };
   674→              return {
   675→                ...task,
   676→                subtasks: [...subtasks, newSubtask],
   677→              };
   678→            }
   679→            return task;
   680→          }),
   681→        }));
   682→
   683→        // Log activity
   684→        get().logActivity(taskId, {
   685→          action: 'created',
   686→          field: 'subtask',
   687→          newValue: subtaskData.title,
   688→        });
   689→      },
   690→
   691→      updateSubtask: (taskId, subtaskId, updates) => {
   692→        set((state) => ({
   693→          tasks: state.tasks.map((task) => {
   694→            if (task.id === taskId && task.subtasks) {
   695→              return {
   696→                ...task,
   697→                subtasks: task.subtasks.map((subtask) =>
   698→                  subtask.id === subtaskId ? { ...subtask, ...updates } : subtask
   699→                ),
   700→              };
   701→            }
   702→            return task;
   703→          }),
   704→        }));
   705→
   706→        // Log activity
   707→        get().logActivity(taskId, {
   708→          action: 'updated',
   709→          field: 'subtask',
   710→          newValue: JSON.stringify(updates),
   711→        });
   712→      },
   713→
   714→      deleteSubtask: (taskId, subtaskId) => {
   715→        const task = get().tasks.find((t) => t.id === taskId);
   716→        const subtask = task?.subtasks?.find((s) => s.id === subtaskId);
   717→
   718→        set((state) => ({
   719→          tasks: state.tasks.map((task) => {
   720→            if (task.id === taskId && task.subtasks) {
   721→              return {
   722→                ...task,
   723→                subtasks: task.subtasks.filter((s) => s.id !== subtaskId),
   724→              };
   725→            }
   726→            return task;
   727→          }),
   728→        }));
   729→
   730→        // Log activity
   731→        if (subtask) {
   732→          get().logActivity(taskId, {
   733→            action: 'created',
   734→            field: 'subtask',
   735→            oldValue: subtask.title,
   736→          });
   737→        }
   738→      },
   739→
   740→      toggleSubtask: (taskId, subtaskId) => {
   741→        set((state) => ({
   742→          tasks: state.tasks.map((task) => {
   743→            if (task.id === taskId && task.subtasks) {
   744→              return {
   745→                ...task,
   746→                subtasks: task.subtasks.map((subtask) => {
   747→                  if (subtask.id === subtaskId) {
   748→                    const completed = !subtask.completed;
   749→                    return {
   750→                      ...subtask,
   751→                      completed,
   752→                      completedAt: completed ? new Date().toISOString() : undefined,
   753→                    };
   754→                  }
   755→                  return subtask;
   756→                }),
   757→              };
   758→            }
   759→            return task;
   760→          }),
   761→        }));
   762→
   763→        // Log activity
   764→        const task = get().tasks.find((t) => t.id === taskId);
   765→        const subtask = task?.subtasks?.find((s) => s.id === subtaskId);
   766→        if (subtask) {
   767→          get().logActivity(taskId, {
   768→            action: 'updated',
   769→            field: 'subtask',
   770→            newValue: subtask.completed ? 'completed' : 'uncompleted',
   771→          });
   772→        }
   773→      },
   774→
   775→      reorderSubtasks: (taskId, subtaskIds) => {
   776→        set((state) => ({
   777→          tasks: state.tasks.map((task) => {
   778→            if (task.id === taskId && task.subtasks) {
   779→              const reorderedSubtasks = subtaskIds
   780→                .map((id, index) => {
   781→                  const subtask = task.subtasks!.find((s) => s.id === id);
   782→                  return subtask ? { ...subtask, order: index } : null;
   783→                })
   784→                .filter((s): s is Subtask => s !== null);
   785→
   786→              return {
   787→                ...task,
   788→                subtasks: reorderedSubtasks,
   789→              };
   790→            }
   791→            return task;
   792→          }),
   793→        }));
   794→
   795→        // Log activity
   796→        get().logActivity(taskId, {
   797→          action: 'updated',
   798→          field: 'subtasks',
   799→          newValue: 'reordered',
   800→        });
   801→      },
   802→
   803→      // ==================== PHASE 5: DEPENDENCY ACTIONS ====================
   804→
   805→      addDependency: (sourceTaskId, targetTaskId) => {
   806→        // Prevent self-dependency
   807→        if (sourceTaskId === targetTaskId) {
   808→          console.error('Task cannot depend on itself');
   809→          return;
   810→        }
   811→
   812→        // Check for circular dependency
   813→        const dependencies = get().dependencies || [];
   814→        const wouldCreateCycle = (source: string, target: string): boolean => {
   815→          if (source === target) return true;
   816→          const childDeps = dependencies.filter((d) => d.sourceTaskId === target);
   817→          return childDeps.some((d) => wouldCreateCycle(source, d.targetTaskId));
   818→        };
   819→
   820→        if (wouldCreateCycle(sourceTaskId, targetTaskId)) {
   821→          console.error('This would create a circular dependency');
   822→          return;
   823→        }
   824→
   825→        const newDependency: SimpleTaskDependency = {
   826→          id: `dep-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
   827→          sourceTaskId,
   828→          targetTaskId,
   829→          createdAt: new Date().toISOString(),
   830→        };
   831→
   832→        set((state) => ({
   833→          dependencies: [...(state.dependencies || []), newDependency],
   834→        }));
   835→
   836→        // Log activity for both tasks
   837→        get().logActivity(sourceTaskId, {
   838→          action: 'created',
   839→          field: 'dependency',
   840→          newValue: `Blocks task ${targetTaskId}`,
   841→        });
   842→
   843→        get().logActivity(targetTaskId, {
   844→          action: 'created',
   845→          field: 'dependency',
   846→          newValue: `Blocked by task ${sourceTaskId}`,
   847→        });
   848→      },
   849→
   850→      removeDependency: (dependencyId) => {
   851→        const dependency = get().dependencies?.find((d) => d.id === dependencyId);
   852→
   853→        set((state) => ({
   854→          dependencies: (state.dependencies || []).filter((d) => d.id !== dependencyId),
   855→        }));
   856→
   857→        // Log activity
   858→        if (dependency) {
   859→          get().logActivity(dependency.sourceTaskId, {
   860→            action: 'updated',
   861→            field: 'dependency',
   862→            oldValue: `Blocks task ${dependency.targetTaskId}`,
   863→          });
   864→
   865→          get().logActivity(dependency.targetTaskId, {
   866→            action: 'updated',
   867→            field: 'dependency',
   868→            oldValue: `Blocked by task ${dependency.sourceTaskId}`,
   869→          });
   870→        }
   871→      },
   872→
   873→      getBlockers: (taskId) => {
   874→        const dependencies = get().dependencies || [];
   875→        const blockerIds = dependencies
   876→          .filter((d) => d.targetTaskId === taskId)
   877→          .map((d) => d.sourceTaskId);
   878→
   879→        return get().tasks.filter((t) => blockerIds.includes(t.id));
   880→      },
   881→
   882→      getBlocked: (taskId) => {
   883→        const dependencies = get().dependencies || [];
   884→        const blockedIds = dependencies
   885→          .filter((d) => d.sourceTaskId === taskId)
   886→          .map((d) => d.targetTaskId);
   887→
   888→        return get().tasks.filter((t) => blockedIds.includes(t.id));
   889→      },
   890→
   891→      // ==================== PHASE A: ARCHIVE ACTIONS ====================
   892→
   893→      archiveTask: (id) => {
   894→        const task = get().tasks.find((t) => t.id === id);
   895→        if (!task) return;
   896→
   897→        const archivedTask: Task = {
   898→          ...task,
   899→          archivedAt: new Date().toISOString(),
   900→        };
   901→
   902→        set((state) => ({
   903→          tasks: state.tasks.filter((t) => t.id !== id),
   904→          archivedTasks: [...(state.archivedTasks || []), archivedTask],
   905→        }));
   906→
   907→        // Log archive action
   908→        get().logActivity(id, {
   909→          action: 'updated',
   910→          field: 'archived',
   911→          newValue: 'true',
   912→        });
   913→      },
   914→
   915→      restoreTask: (id) => {
   916→        const archivedTask = get().archivedTasks?.find((t) => t.id === id);
   917→        if (!archivedTask) return;
   918→
   919→        // Remove archivedAt field when restoring
   920→        const { archivedAt, ...restoredTask } = archivedTask;
   921→
   922→        set((state) => ({
   923→          archivedTasks: (state.archivedTasks || []).filter((t) => t.id !== id),
   924→          tasks: [...state.tasks, restoredTask as Task],
   925→        }));
   926→
   927→        // Log restore action
   928→        get().logActivity(id, {
   929→          action: 'updated',
   930→          field: 'archived',
   931→          oldValue: 'true',
   932→          newValue: 'false',
   933→        });
   934→      },
   935→
   936→      deleteArchivedTask: (id) => {
   937→        set((state) => ({
   938→          archivedTasks: (state.archivedTasks || []).filter((t) => t.id !== id),
   939→        }));
   940→      },
   941→
   942→      getArchivedTasks: () => {
   943→        return (get().archivedTasks || []).sort((a, b) => {
   944→          // Sort by archive date (most recent first)
   945→          const dateA = new Date(a.archivedAt || 0).getTime();
   946→          const dateB = new Date(b.archivedAt || 0).getTime();
   947→          return dateB - dateA;
   948→        });
   949→      },
   950→
   951→      autoArchiveCompletedTasks: () => {
   952→        const now = new Date();
   953→        const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
   954→
   955→        const tasksToArchive = get().tasks.filter((task) => {
   956→          // Only archive tasks in "done" status
