  1010→        const state = get();
  1011→        const task = state.tasks.find((t) => t.id === taskId);
  1012→
  1013→        if (!task || !task.timeTracking?.activeTimerStart) {
  1014→          console.warn('No active timer for task:', taskId);
  1015→          return;
  1016→        }
  1017→
  1018→        const startTime = new Date(task.timeTracking.activeTimerStart);
  1019→        const endTime = new Date(now);
