    10→
    11→/**
    12→ * TimeEntryCalendar Component
    13→ * Full calendar view showing time entries as visual blocks
    14→ */
    15→export function TimeEntryCalendar({ onEditEntry }: TimeEntryCalendarProps) {
    16→  const { entries, projects, loadEntries, loadProjects } = useTimeTrackingStore();
    17→
    18→  const [loading, setLoading] = useState(true);
    19→  const [currentDate, setCurrentDate] = useState(new Date());
    20→
    21→  const year = currentDate.getFullYear();
    22→  const month = currentDate.getMonth(); // 0-11
    23→
    24→  useEffect(() => {
    25→    const loadData = async () => {
    26→      setLoading(true);
    27→      try {
    28→        // Load entries for the entire month
    29→        const monthStart = new Date(year, month, 1);
    30→        const monthEnd = new Date(year, month + 1, 0, 23, 59, 59);
    31→
    32→        await Promise.all([
    33→          loadEntries({
    34→            dateRange: 'custom',
    35→            startDate: monthStart.toISOString(),
    36→            endDate: monthEnd.toISOString(),
    37→            projectIds: [],
    38→            tags: [],
    39→            searchQuery: ''
    40→          }),
    41→          loadProjects()
    42→        ]);
    43→      } catch (error) {
    44→        console.error('Failed to load calendar data:', error);
    45→      } finally {
    46→        setLoading(false);
    47→      }
    48→    };
    49→
    50→    loadData();
    51→  }, [loadEntries, loadProjects, year, month]);
    52→
    53→  const handlePreviousMonth = () => {
    54→    setCurrentDate(new Date(year, month - 1, 1));
    55→  };
