    62→    setCurrentDate(new Date());
    63→  };
    64→
    65→  if (loading) {
    66→    return (
    67→      <div className="flex items-center justify-center py-12">
    68→        <div className="text-text-light-secondary dark:text-text-dark-secondary">
    69→          Loading calendar...
    70→        </div>
    71→      </div>
    72→    );
    73→  }
    74→
    75→  const monthName = new Date(year, month, 1).toLocaleDateString('en-US', {
    76→    month: 'long',
    77→    year: 'numeric'
    78→  });
    79→
    80→  // Get day of week for first day of month (0 = Sunday)
    81→  const firstDayOfWeek = new Date(year, month, 1).getDay();
    82→  const daysInMonth = new Date(year, month + 1, 0).getDate();
    83→
    84→  // Group entries by date
    85→  const entriesByDate = new Map<string, TimeEntry[]>();
