    87→    const date = new Date(entry.startTime).toISOString().split('T')[0];
    88→    if (!entriesByDate.has(date)) {
    89→      entriesByDate.set(date, []);
    90→    }
    91→    entriesByDate.get(date)!.push(entry);
    92→  });
    93→
    94→  // Create calendar grid
    95→  const calendarDays: (number | null)[] = [];
    96→  for (let i = 0; i < firstDayOfWeek; i++) {
    97→    calendarDays.push(null); // Empty cells before month starts
    98→  }
    99→  for (let day = 1; day <= daysInMonth; day++) {
   100→    calendarDays.push(day);
   101→  }
   102→
   103→  const getProjectColor = (projectId?: string) => {
   104→    if (!projectId) return '#94A3B8'; // Default gray
   105→    return projects.find(p => p.id === projectId)?.color || '#94A3B8';
   106→  };
   107→
   108→  const getProjectName = (projectId?: string) => {
   109→    if (!projectId) return 'No Project';
   110→    return projects.find(p => p.id === projectId)?.name || 'Unknown';
   111→  };
   112→
   113→  return (
